BEGIN TRANSACTION;
CREATE TABLE armor (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        name TEXT NOT NULL UNIQUE,
        category TEXT,  -- Light, Medium, Heavy, Shield
        ac_bonus INTEGER,
        max_dex INTEGER,
        check_penalty INTEGER,
        spell_failure INTEGER,
        speed_30 TEXT,
        speed_20 TEXT,
        weight REAL,
        cost TEXT
    );
