CREATE TABLE attacks (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        monster_id INTEGER NOT NULL,
        group_id INTEGER,
        att_name TEXT,
        att_count INTEGER,
        is_standard INTEGER,
        weapon_nature TEXT,
        att_mode TEXT,
        use_category TEXT,
        dmg_die TEXT,
        crit_range TEXT,
        crit_mult INTEGER,
        str_mult REAL,
        att_roll_enh INTEGER DEFAULT 0,
        dmg_enh INTEGER DEFAULT 0,
        dmg_composite TEXT,
        dmg_text TEXT,
        weapon_text TEXT, reach TEXT,
        FOREIGN KEY (monster_id) REFERENCES monsters(id)
    );
