CREATE TABLE "monsters" (
    id INTEGER PRIMARY KEY,
    name TEXT NOT NULL,
    size TEXT,
    type TEXT,
    descriptor TEXT,
    hd_count INTEGER,
    hit_dice TEXT,
    initiative TEXT,
    speed TEXT,
    armor_class TEXT,
    base_attack INTEGER,
    grapple TEXT,
    attack TEXT,
    full_attack TEXT,
    space TEXT,
    reach TEXT,
    special_attacks TEXT,
    special_qualities TEXT,
    skills TEXT,
    feats TEXT,
    bonus_feats TEXT,
    saves TEXT,
    fort_save_type TEXT,
    ref_save_type TEXT,
    will_save_type TEXT,
    str INTEGER,
    dex INTEGER,
    con INTEGER,
    int INTEGER,
    wis INTEGER,
    cha INTEGER,
    environment TEXT,
    organization TEXT,
    challenge_rating REAL,
    treasure TEXT,
    alignment TEXT,
    advancement TEXT,
    special_abilities TEXT,
    reference TEXT,
    level_adjustment TEXT,
    altname TEXT
, advancement_type TEXT, adv_max_hd INTEGER, adv_size_thresholds TEXT, ac_total INTEGER, ac_touch INTEGER, ac_flat_footed INTEGER);
